declare module "*.css" {
  const content: string;
  export default content;
}

declare module "*.js" {
  const content: string;
  export default content;
}

declare module "*.jpg" {
  const content: ArrayBuffer;
  export default content;
}

declare module "*.woff2" {
  const content: ArrayBuffer;
  export default content;
}

declare module "*.ttf" {
  const content: ArrayBuffer;
  export default content;
}
